mapper.select:
WITH LATEST_DEPLOY AS ( /* 페이지별 최신 배포 이력 1건 추출 — INNER JOIN 후 ROW_NUMBER로 ORA-01799 우회 */ SELECT p2.PAGE_ID AS PAGE_ID_KEY, h.INSTANCE_ID, ROW_NUMBER() OVER ( PARTITION BY p2.PAGE_ID ORDER BY h.LAST_MODIFIED_DTIME DESC NULLS LAST ) AS RN FROM SPW_CMS_PAGE p2 INNER JOIN FWK_CMS_FILE_SEND_HIS h ON h.FILE_ID LIKE p2.PAGE_ID || '%.html' OR h.FILE_ID LIKE p2.PAGE_ID || '%.tsx' WHERE p2.PAGE_TYPE = 'REACT' AND p2.APPROVE_STATE = 'APPROVED' AND p2.USE_YN = 'Y' ) SELECT * FROM ( SELECT INNER_QRY.*, ROWNUM AS RNUM FROM ( SELECT p.PAGE_ID AS pageId, p.PAGE_NAME AS pageName, p.CREATE_USER_NAME AS createUserName, TO_CHAR(p.BEGINNING_DATE, 'YYYY-MM-DD') AS beginningDate, TO_CHAR(p.EXPIRED_DATE, 'YYYY-MM-DD') AS expiredDate,
si.INSTANCE_ID AS instanceId, si.INSTANCE_IP AS instanceIp, si.INSTANCE_PORT AS instancePort FROM SPW_CMS_PAGE p LEFT JOIN LATEST_DEPLOY ld ON ld.PAGE_ID_KEY = p.PAGE_ID AND ld.RN = 1 LEFT JOIN FWK_CMS_SERVER_INSTANCE si ON si.INSTANCE_ID = ld.INSTANCE_ID
ORDER BY p.LAST_MODIFIED_DTIME DESC NULLS LAST ) INNER_QRY WHERE ROWNUM <= #{endRow} ) WHERE RNUM > #{offset}
